sea_vert = '\n#version 110\n\n#define DETAIL_LEVEL 3\n\n#define MAX_LIGHTS 1\n\nvarying vec3 normal;\nvarying vec4 posView;\n\nvarying vec2 noiseTexCoord;\nvarying vec2 aoTexCoord;\n\nfloat FogEyeRadial(vec4 Rh)\n{\n    vec4 Re = Rh / Rh.w;\n    return length(Re);\n}\n\nvoid main(void) \n{\n#if DETAIL_LEVEL > 0\n    vec4 posViewSpace = gl_ModelViewMatrix * vec4(gl_Vertex.xyz, 1.0);\n#endif\n\n    gl_Position = gl_ModelViewProjectionMatrix * vec4(gl_Vertex.xyz, 1.0);\n    gl_FrontColor = gl_Color;\n    gl_FogFragCoord = FogEyeRadial(gl_ModelViewMatrix * vec4(gl_Vertex.rgb, 1.0));\n\n#if DETAIL_LEVEL > 0\n    aoTexCoord = gl_MultiTexCoord0.xy;\n\n    vec3 tempNormal;\n    tempNormal.z = floor(gl_MultiTexCoord1.x / 64.0) - 1.0 ; \n    tempNormal.y = floor(fract(gl_MultiTexCoord1.x / 64.0) * 4.0) - 1.0; \n    tempNormal.x = floor(fract(gl_MultiTexCoord1.x / 16.0) * 4.0) - 1.0; \n\n    vec2 tempNoise;\n    tempNoise.x = floor(fract(gl_MultiTexCoord1.x / 4.0) * 2.0); \n    tempNoise.y = floor(fract(gl_MultiTexCoord1.x / 2.0) * 2.0); \n\n    noiseTexCoord = tempNoise.xy;\n    normal = (gl_NormalMatrix * tempNormal.xyz);\n\n    posView = posViewSpace;\n#endif\n}\n'
